```json
{
  "global": "Locate the newsletter signup form on the fashion website, enter a valid email address, and submit the form to complete the subscription.",
  "subtasks": [
    {
      "subtask": "Navigate to the newsletter signup entry point",
      "atomics": [
        "Scroll to the footer of the homepage to find a newsletter signup section",
        "Alternatively, look for a modal, banner, or dedicated '/newsletter' page link",
        "Click or focus the newsletter signup area to activate the form"
      ]
    },
    {
      "subtask": "Fill in the required signup fields",
      "atomics": [
        "Click the email input field within the newsletter form",
        "Type a valid email address into the email input field",
        "Fill any additional required fields (e.g., first name) if present"
      ]
    },
    {
      "subtask": "Submit the newsletter signup form",
      "atomics": [
        "Click the subscribe/submit button associated with the newsletter form",
        "Handle any CAPTCHA or consent checkbox if it appears before submission"
      ]
    },
    {
      "subtask": "Confirm successful subscription",
      "atomics": [
        "Check for a success message, toast notification, or confirmation text on the page",
        "Verify the confirmation message indicates subscription was accepted (e.g., 'Thank you for subscribing')"
      ]
    }
  ],
  "global_atomics": [
    "Verify no error messages (e.g., 'invalid email', 'already subscribed') are displayed after submission"
  ],
  "gold_actions": {
    "global": "Scroll to footer newsletter form, type email into input[type='email'], click subscribe button, and assert success confirmation text is visible.",
    "subtasks": [
      {
        "subtask": "Navigate to the newsletter signup entry point",
        "atomics": [
          "scroll(direction='down', amount='page_bottom') to reveal footer newsletter widget",
          "locate element matching CSS selector 'footer .newsletter, footer form, #newsletter-signup' or scan for banner/modal with keyword 'newsletter'",
          "click(element='newsletter_section_anchor_or_input') to focus the signup form"
        ]
      },
      {
        "subtask": "Fill in the required signup fields",
        "atomics": [
          "click(element='input[type=\"email\"]') within the newsletter form",
          "type(text='user@example.com') into the focused email input field",
          "type(text='User') into first-name input if field is present and required"
        ]
      },
      {
        "subtask": "Submit the newsletter signup form",
        "atomics": [
          "click(element='button[type=\"submit\"], input[type=\"submit\"], .subscribe-btn') within the newsletter form",
          "click(element='input[type=\"checkbox\"]#consent') if a GDPR/consent checkbox is required before submission"
        ]
      },
      {
        "subtask": "Confirm successful subscription",
        "atomics": [
          "assert_visible(selector='.success-message, .confirmation, [class*=\"success\"]') or check page text contains 'subscribed' / 'thank you'",
          "screenshot() or read_page_text() to capture the confirmation state as evidence"
        ]
      }
    ],
    "global_atomics": [
      "assert_not_visible(selector='.error-message, .alert-danger') and confirm no 'invalid email' or 'already registered' error text is present in the DOM"
    ]
  }
}
```
